head.script:
       /**
		 * 화면 초기화에 필요한 로직을 수행한다.
		 * @param
		 * @return
		 */
		scwin.initScreen = function() {
				/**
			 *  Drag & Drop 이벤트 처리용 함수호출
			 * @param
			 * @return
			 */
			var filedragdom = _grdMultiFile.render;                                          // 첨부파일 정보가 보여질 그리드ID
			filedragdom.addEventListener("dragover", scwin.fileDragHandler, false);
	    	filedragdom.addEventListener("dragenter", scwin.fileDragHandler, false);  // for ie
			filedragdom.addEventListener("dragleave", scwin.fileDragHandler, false);
			filedragdom.addEventListener("drop", scwin.fileDropHandler, false);

			/*********************** Drag & Drop 끝 ***********************/
		}

      /**********************************************************
      첨부파일 처리
      **********************************************************/
       /**
        * 첨부파일 선택이후 호출되는 콜백함수
        * @param  mpdMultiAtchFile.getFileInfos() 선택된 파일정보
        * @return
        */
       scwin._multiSelectCallback = function() {
       	//공통제공 함수호출
       	fileLib.multiSelectCallback(_mpdMultiAtchFile, _dltFile);
       };

       /**
        * 등록하고자 선택된 첨부파일 삭제처리(단, 저장전에만 가능함)
        * @param
        * @return
        */
      scwin._btnDelMultiFile_onclick = function() {
		fileLib.multiDeleteFileList(_grdMultiFile, _mpdMultiAtchFile, _dltFile);
	};

       /**
        * 파일 임시저장(업로드) 이후 호출되는 콜백함수
        * @param data 업로드된 파일정보(원본파일명, 임시저장소 저장파일명, 파일사이즈)
        * @return
        */
	scwin._mpdMultiAtchFile_ondone = function(data) {
		//첨부파일정보 셋팅
		var rtnYn = fileLib.dataListSetting(_dltFile, data);
		if (rtnYn) {
			// comLib.confirm($p, utilLib.getMessage("SCM.INFO.00321"), "scwin.saveConfirmCallback");
			$p.parent().scwin.saveConfirmCallback();
		}
	};


	/**
	 * 프로그래스바를 상태, 프로그래스바 사용시 필요함.
	 * @param info 파일전송상태값
	 * @return
	 */
	scwin._mpdMultiAtchFile_onprogress = function(info) {
		var rowidx = _dltFile.getMatchedIndex("name", info.fileName);

		$(".multiFile table tbody tr:eq("+rowidx+") td.pro-bar .w2grid_input").text(info.percentData+"%");
		$(".multiFile table tbody tr:eq("+rowidx+") td.pro-bar .w2grid_input").css("width", info.percentData+"%");
	};

		/*********************** Drag & Drop 시작 ***********************/
		/**
		 * drop할때 발생하는 이벤트
		 * @param
		 * @return
		 */
		/*
		_mpdMultiAtchFile._handleOndrop = function(e) {
		    try {
		        $W._c.stopEvent(e);

		        var _6c = e.dataTransfer.files;

		         for (var i = 0; i < _6c.length; i++) {
		                if ($.inArray(_6c[i].name, this.fileNameArr) == -1) {
		                    this.fileArray.push(_6c[i]);
		                    this.fileNameArr.push(_6c[i].name);
		                    this._inx++;
		                } else {
		                    comLib.alert($p, "파일이 이미 있습니다.  (" + _6c[i].name + ")");
		                }
		            }
		      } catch (e) {
		      	$W.exception.printStackTrace(e, null, this);
		      }
		};
		*/
		/**
		 *  file drag
		 * @param  event
		 * @return
		 */
		scwin.fileDragHandler = function(e){
			WebSquare.event.stopEvent(e);
			//e.target.className = (e.type == "dragover" ? "hover" : "");
		}

		/**
		 * file drop
		 * @param
		 * @return
		 */
		scwin.fileDropHandler = function(e){
			scwin.fileDragHandler(e);
			_mpdMultiAtchFile._handleOndrop(e);				//멀티컨포넌트 ID로 셋팅
			scwin._multiSelectCallback();
		}


		/**
		 * 첨부파일 다운로드
		 * @param event
		 * @return 첨부파일
		 */
		scwin._grdMultiFile_oncellclick = function(row,col) {
			if ( _grdMultiFile.getFocusedColumnID() == "name") {
				var row = _grdMultiFile.getFocusedRowIndex();
				var atchflId = _dltFile.getCellData( row, "atchflId" );       	//첨부파일 ID
				var fileSeq = _dltFile.getCellData( row, "fileSeq" );       	//첨부파일 ID

				if (atchflId == null || atchflId == "") {
					comLib.alert($p, utilLib.getMessage( "SCM.INFO.00179","첨부파일ID"));
					return;
				}
				if (fileSeq == null || fileSeq == "") {
					comLib.alert($p, utilLib.getMessage( "SCM.INFO.00179","첨부파일순번"));
					return;
				}

				if (atchflId != null && atchflId != '' ) {
					var dmaTest = { "atchflId" : atchflId, "fileSeq" : fileSeq };
					var xmlValue = JSON.stringify( dmaTest );
					// $w.download( "/sc/file/downloadAtchFileOne.do" , xmlValue, "get");
					comLib.downloadAtchfl( "/sc/file/downloadAtchFileOne.do" , xmlValue, "get");
				}
			}
		};

		/**
		 * 첨부파일 일괄 다운로드
		 * @param _dltFile
		 * @return 압축파일
		 */
		scwin._btnAllDown_onclick = function() {
			var idxArr =_grdMultiFile.getCheckedJSON("chk");
			var idxArr1 = _grdMultiFile.getCheckedIndex( "chk" );
			if (idxArr.length > 0 ) {
				var xmlValue = JSON.stringify(idxArr);
				// $w.download( "/sc/file/downloadAtchFile.do" , xmlValue, "post");
				comLib.downloadAtchfl( "/sc/file/downloadAtchFile.do" , xmlValue, "post");
			} else {
				comLib.alert($p, "선택된 데이터가 없습니다.");
			}
		}

		/**
		 * 첨부파일 그리드 클리어
		 * @param
		 * @return
		 */
		 scwin._fileReset = function() {
		 	_dltFile.setJSON([]);
		 	_mpdMultiAtchFile.removeAllFiles();
		 };
